import{_ as n,j as a,o as i,v as t}from"./chunks/framework.gVsiwu-7.js";const s=JSON.parse('{"title":"Kafka Brokers là gì ?","description":"","frontmatter":{"footer":true,"title":"Kafka Brokers là gì ?","authors":["lethanh"],"date":"2024-06-10T00:00:00.000Z","outline":"deep","draft":true,"group":"2.1 Kafka"},"headers":[{"level":2,"title":"Kafka Brokers là gì ?","slug":"kafka-brokers-la-gi","link":"#kafka-brokers-la-gi","children":[]},{"level":2,"title":"Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers","slug":"vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers","link":"#vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers","children":[]},{"level":2,"title":"Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers","slug":"vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers","link":"#vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers","children":[]},{"level":2,"title":"Topics và partitions","slug":"topics-va-partitions","link":"#topics-va-partitions","children":[{"level":3,"title":"Topics","slug":"topics","link":"#topics","children":[]},{"level":3,"title":"partitions","slug":"partitions","link":"#partitions","children":[{"level":4,"title":"Cách Kafka Broker map record đến partition.","slug":"cach-kafka-broker-map-record-đen-partition","link":"#cach-kafka-broker-map-record-đen-partition","children":[{"level":5,"title":"Cách 1: Xác định partition tại thời điểm tạo object ProducerRecord","slug":"cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord","link":"#cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord","children":[]},{"level":5,"title":"Cách 2: Xác định tự động partition tại bởi lib Producer trước khi gửi đến Brokers","slug":"cach-2-xac-đinh-tu-đong-partition-tai-boi-lib-producer-truoc-khi-gui-đen-brokers","link":"#cach-2-xac-đinh-tu-đong-partition-tai-boi-lib-producer-truoc-khi-gui-đen-brokers","children":[]}]}]},{"level":3,"title":"Offsets","slug":"offsets","link":"#offsets","children":[]},{"level":3,"title":"Xác định số lượng partition sử dụng","slug":"xac-đinh-so-luong-partition-su-dung","link":"#xac-đinh-so-luong-partition-su-dung","children":[]},{"level":3,"title":"Tạo một topic","slug":"tao-mot-topic","link":"#tao-mot-topic","children":[]},{"level":3,"title":"Segments","slug":"segments","link":"#segments","children":[]}]},{"level":2,"title":"Một số lưu ý về Kafka Brokers","slug":"mot-so-luu-y-ve-kafka-brokers","link":"#mot-so-luu-y-ve-kafka-brokers","children":[]}],"relativePath":"study/thanhlv-study-2024/2024-06-10-kafka-brokers.md","filePath":"study/thanhlv-study-2024/2024-06-10-kafka-brokers.md","lastUpdated":1720975828000}'),e={name:"study/thanhlv-study-2024/2024-06-10-kafka-brokers.md"},c=[t('<nav class="table-of-contents"><ul><li><a href="#kafka-brokers-la-gi">Kafka Brokers là gì ?</a></li><li><a href="#vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers">Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers</a></li><li><a href="#vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers">Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers</a></li><li><a href="#topics-va-partitions">Topics và partitions</a><ul><li><a href="#topics">Topics</a></li><li><a href="#partitions">partitions</a><ul><li><a href="#cach-kafka-broker-map-record-đen-partition">Cách Kafka Broker map record đến partition.</a><ul><li><a href="#cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord">Cách 1: Xác định partition tại thời điểm tạo object ProducerRecord</a></li><li><a href="#cach-2-xac-đinh-tu-đong-partition-tai-boi-lib-producer-truoc-khi-gui-đen-brokers">Cách 2: Xác định tự động partition tại bởi lib Producer trước khi gửi đến Brokers</a></li></ul></li></ul></li><li><a href="#offsets">Offsets</a></li><li><a href="#xac-đinh-so-luong-partition-su-dung">Xác định số lượng partition sử dụng</a></li><li><a href="#tao-mot-topic">Tạo một topic</a></li><li><a href="#segments">Segments</a></li></ul></li><li><a href="#mot-so-luu-y-ve-kafka-brokers">Một số lưu ý về Kafka Brokers</a></li></ul></nav><h1 id="overview-bai-viet-ve-kafka-brokers-la-gi" tabindex="-1">Overview bài viết về Kafka Brokers là gì ? <a class="header-anchor" href="#overview-bai-viet-ve-kafka-brokers-la-gi" aria-label="Permalink to &quot;Overview bài viết về Kafka Brokers là gì ?&quot;">​</a></h1><ul><li>Bài này sẽ giải thích cách kafka Broker hoạt động và lưu trữ trong Kafka event streaming platform</li><li>Mô tả cách Kafka Brokers xử lý các yêu cầu từ client cho việc ghi và đọc records.</li><li>Hiểu về Topic và Partitions</li><li>Sử dụng JMX metrics để kiểm tra Brokers</li></ul><h2 id="kafka-brokers-la-gi" tabindex="-1">Kafka Brokers là gì ? <a class="header-anchor" href="#kafka-brokers-la-gi" aria-label="Permalink to &quot;Kafka Brokers là gì ?&quot;">​</a></h2><ul><li>Kafka Brokers hay có thể gọi là Kafka server trong Kafka architecture và nó sẽ đóng vai trò lưu trữ dữ liệu(Storage layer) và nó có thể chạy thành một cluster và nó có thể mở rộng ra nhiều data centers. <img src="/assets/kafka-architecture-view.B_rra7lS.png" alt="kafka-architecture-view.png"></li><li>Kafka Brokers chịu trách nghiệm quản lý dữ liệu( Bao gồm lưu trữ, đọc và replication(Tạo bản sao để sao lưu) ), quản lý topic và partition và quản lý offset.</li><li>Tất nhiên, Kafka Brokers cũng nhận và xử lý trực tiếp các request từ client. <img src="/assets/kafka-handler-request.tA_aT67K.jpg" alt="kafka-handler-request.jpg"></li></ul><h2 id="vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers" tabindex="-1">Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers <a class="header-anchor" href="#vai-tro-cua-kafka-brokers-voi-produce-khi-produce-gui-record-đen-brokers" aria-label="Permalink to &quot;Vai trò của Kafka Brokers với Produce khi Produce gửi record đến Brokers&quot;">​</a></h2><ul><li>Khi Produce muốn gửi Record đến Broker, Client Produce gửi records đến Broker đeer lưu trữ và consumer client có thể đọc các record đó sau. <img src="/assets/kafka-produce.MttxNzo5.jpg" alt="kafka-produce.jpg"> Hình ảnh phía trên mô tả Produce gửi record đến Brokers, trong thực tế, nhiều Client Produce sẽ giao tiếp với 1 số các Brokers trong cụm.</li></ul><h2 id="vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers" tabindex="-1">Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers <a class="header-anchor" href="#vai-tro-cua-kafka-brokers-voi-consumer-khi-consumer-nhan-record-tu-brokers" aria-label="Permalink to &quot;Vai trò của Kafka Brokers với Consumer khi Consumer nhận record từ Brokers&quot;">​</a></h2><p>Sau khi nói về yêu cầu của Produce chúng ta sẽ nói đến Consumer.</p><ul><li>Consumer client đưa ra yêu cầu đến Broker để đọc(Sử dụng) các Record từ một topic được các Produce gửi trước đó đên Broker. <img src="/assets/kafka-Consumer.PLcOqiQl.jpg" alt="kafka-Consumer.jpg"></li><li>Một điều quan trọng là sử dụng Record sẽ không làm ảnh hưởng đến việc lưu dữ liệu(Không bị mất sau khi đọc) hoặc việc sử dụng Record bởi các Consumer khác(Các consumer khác vẫn có thể đọc)</li></ul><h2 id="topics-va-partitions" tabindex="-1">Topics và partitions <a class="header-anchor" href="#topics-va-partitions" aria-label="Permalink to &quot;Topics và partitions&quot;">​</a></h2><h3 id="topics" tabindex="-1">Topics <a class="header-anchor" href="#topics" aria-label="Permalink to &quot;Topics&quot;">​</a></h3><ul><li>Kafka brokers sử dụng File system để lưu trữ bằng cách nối thêm các Record đến cuối cùng file trong một topic.</li><li>Một topic đại diện cho tên của Folder chưa tệp Kafka nối thêm các Record <img src="/assets/kafka-topic-1.AVPSldcv.jpg" alt="kafka-topic-1.jpg"></li><li>Kafka Brokers sẽ nhận key-value message dưới dạng raw byte, lưu trữ và phục vụ các yêu cầu đọc với cùng định dạng(Raw data). <ul><li>Kafka Brokers không biết về data type của Record(Chỉ nhận được các byte), bằng cách làm việc với raw byte, Brokers không mất thời gian deserializing hoặc serializing dữ liệu nên mạng lại hiệu suất cao hơn.</li></ul></li></ul><h3 id="partitions" tabindex="-1">partitions <a class="header-anchor" href="#partitions" aria-label="Permalink to &quot;partitions&quot;">​</a></h3><ul><li>Các topic sẽ đươc partition, một Partition là một số nguyên(number) bắt đầu từ 0. Vì vậy nếu một topic có 3 partition thì sẽ có số partition là 0, 1, 2.</li><li>Kafka brokers gắn số partition và đuôi của folder topic với format <code>{Topic name}-{partition number}</code>. <ul><li>Ví dụ một Topic tên <code>my-topic-2</code> có <code>5</code> partition thì tên sẽ như sau : <code>my-topic-2-0</code>, <code>my-topic-2-1</code>, <code>my-topic-2-2</code>, <code>my-topic-2-3</code>, , <code>my-topic-2-4</code>, <img src="/assets/kafka-partition-number.H1MC9uuH.jpg" alt="kafka-partition-number.jpg"></li></ul></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>│   ....</span></span>\n<span class="line"><span>│   recovery-point-offset-checkpoint</span></span>\n<span class="line"><span>│   replication-offset-checkpoint</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-0</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-1</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-2</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-3</span></span>\n<span class="line"><span>│       00000000000000000000.index</span></span>\n<span class="line"><span>│       00000000000000000000.log</span></span>\n<span class="line"><span>│       00000000000000000000.timeindex</span></span>\n<span class="line"><span>│       leader-epoch-checkpoint</span></span>\n<span class="line"><span>│       partition.metadata</span></span>\n<span class="line"><span>│</span></span>\n<span class="line"><span>├───my-topic-2-4</span></span>\n<span class="line"><span>│      00000000000000000000.index</span></span>\n<span class="line"><span>│      00000000000000000000.log</span></span>\n<span class="line"><span>│      00000000000000000000.timeindex</span></span>\n<span class="line"><span>│      leader-epoch-checkpoint</span></span>\n<span class="line"><span>│      partition.metadata</span></span></code></pre></div><ul><li>Nhìn vào folder chúng ta có thể dễ hiểu được với tên topic là một nhóm dữ liệu và partititon là các đơn vị lưu trữ.</li><li>Trong hầu hết các case, số lượng của Partition càng cao thì throughput(Thông lượng) sẽ càng cao.</li></ul><h4 id="cach-kafka-broker-map-record-đen-partition" tabindex="-1">Cách Kafka Broker map record đến partition. <a class="header-anchor" href="#cach-kafka-broker-map-record-đen-partition" aria-label="Permalink to &quot;Cách Kafka Broker map record đến partition.&quot;">​</a></h4><ul><li>Producer client sẽ xác định Topic và partition cho record trước khi gửi nó đến Broker. <img src="/assets/kafka_broker-map-record-to-partition.QBNlkRTb.png" alt="kafka_broker-map-record-to-partition.png"></li><li>Thực tế xác định partition chúng ta có thể chia ra làm 2 cách như sau:</li></ul><h5 id="cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord" tabindex="-1">Cách 1: Xác định partition tại thời điểm tạo object ProducerRecord <a class="header-anchor" href="#cach-1-xac-đinh-partition-tai-thoi-điem-tao-object-producerrecord" aria-label="Permalink to &quot;Cách 1: Xác định partition tại thời điểm tạo object ProducerRecord&quot;">​</a></h5><p>Khi xây dựng ProducerRecord object, bạn set partition cho ProducerRecord thì producer sẽ sử dụng partition đó và gửi lên Broker.</p><details class="details custom-block"><summary>Xác định partition tại thời điểm tạo object ProducerRecord</summary><p><img src="/assets/map-partition-at-create-obj-ProducerRecord.by3wtdu7.png" alt="map-partition-at-create-obj-ProducerRecord.png"><img src="/assets/map-partition-at-create-obj-ProducerRecord-1.-mc7TllN.png" alt="map-partition-at-create-obj-ProducerRecord-1.png"></p></details><h5 id="cach-2-xac-đinh-tu-đong-partition-tai-boi-lib-producer-truoc-khi-gui-đen-brokers" tabindex="-1">Cách 2: Xác định tự động partition tại bởi lib Producer trước khi gửi đến Brokers <a class="header-anchor" href="#cach-2-xac-đinh-tu-đong-partition-tai-boi-lib-producer-truoc-khi-gui-đen-brokers" aria-label="Permalink to &quot;Cách 2: Xác định tự động partition tại bởi lib Producer trước khi gửi đến Brokers&quot;">​</a></h5><ul><li>Đối với java, thư viện sẽ sử dụng class <code>org.apache.kafka.clients.producer.internals.DefaultPartitioner</code> để xác định partition trước khi gửi đến.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>public class DefaultPartitioner implements Partitioner {</span></span>\n<span class="line"><span>    private final StickyPartitionCache stickyPartitionCache = new StickyPartitionCache();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public DefaultPartitioner() {</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public void configure(Map&lt;String, ?&gt; configs) {</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public int partition(String topic, Object key, byte[] keyBytes, Object value, byte[] valueBytes, Cluster cluster) {</span></span>\n<span class="line"><span>        return this.partition(topic, key, keyBytes, value, valueBytes, cluster, cluster.partitionsForTopic(topic).size());</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public int partition(String topic, Object key, byte[] keyBytes, Object value, byte[] valueBytes, Cluster cluster, int numPartitions) {</span></span>\n<span class="line"><span>        return keyBytes == null ? this.stickyPartitionCache.partition(topic, cluster) : Utils.toPositive(Utils.murmur2(keyBytes)) % numPartitions;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public void close() {</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public void onNewBatch(String topic, Cluster cluster, int prevPartition) {</span></span>\n<span class="line"><span>        this.stickyPartitionCache.nextPartition(topic, cluster, prevPartition);</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre></div><p>Trong đoạn mã trên:</p><ol><li>partition Method: <ul><li>Method <code>partition</code> là nơi logic xác định <code>partition</code> được thực hiện.</li><li><code>Cluster</code> chứa thông tin về <code>cluster</code> cũng như các thông tin về <code>partition</code> của <code>topic</code>.</li><li><code>keyBytes</code> là mảng byte của khóa (nếu có).</li><li><code>valueBytes</code> là mảng byte của giá trị(data).</li></ul></li><li>Key-based Partitioning <ul><li>Nếu <code>keyBytes !== null</code> thì key-bash partition sẽ được thực hiện.</li><li>method <code>partition</code> sẽ sử dụng hàm băm <code>murmur2</code> để tính toán giá trị băm của key. <ul><li>Method <code>toPositive</code> sẽ giúp dữ liệu trả về luôn là số dương</li></ul></li><li>Giá trị hash sẽ được chia cho số lượng <code>partition(numPartitions)</code> để xác định <code>partition</code> sẽ được lưu trữ.<details class="details custom-block"><summary>Cùng 1 key sẽ được lưu vào cùng một partition</summary><p>Vì sử dụng key tính ra mã băm sau đó chia cho số lượng partition, vì vậy các <code>record</code> có cùng 1 key sẽ được lưu trên cùng một partition.</p><p>Điều này đảm bảo rằng các bản ghi có cũng key sẽ được lưu trữ trong cùng một partition, giúp duy trì order của các Record có cùng key.</p></details></li></ul></li><li>sticky Partition Cache</li></ol><ul><li>Thực tế, với kafka phiên bản trước <code>2.4</code> thì với trường hợp <code>key == null</code> thì partition sẽ sử dụng <code>Round-robin</code> bằng cách có 1 biến <code>count</code> theo <code>topic</code> và chia cho số lượng partition để được <code>Round-robin</code></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>package org.apache.kafka.clients.producer.internals;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import ...</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>public class StickyPartitionCache {</span></span>\n<span class="line"><span>    private final ConcurrentMap&lt;String, Integer&gt; indexCache = new ConcurrentHashMap();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public StickyPartitionCache() {</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public int partition(String topic, Cluster cluster) {</span></span>\n<span class="line"><span>        Integer part = (Integer)this.indexCache.get(topic);</span></span>\n<span class="line"><span>        return part == null ? this.nextPartition(topic, cluster, -1) : part;</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public int nextPartition(String topic, Cluster cluster, int prevPartition) {</span></span>\n<span class="line"><span>        List&lt;PartitionInfo&gt; partitions = cluster.partitionsForTopic(topic);</span></span>\n<span class="line"><span>        Integer oldPart = (Integer)this.indexCache.get(topic);</span></span>\n<span class="line"><span>        Integer newPart = oldPart;</span></span>\n<span class="line"><span>        if (oldPart != null &amp;&amp; oldPart != prevPartition) {</span></span>\n<span class="line"><span>            return (Integer)this.indexCache.get(topic);</span></span>\n<span class="line"><span>        } else {</span></span>\n<span class="line"><span>            List&lt;PartitionInfo&gt; availablePartitions = cluster.availablePartitionsForTopic(topic);</span></span>\n<span class="line"><span>            if (availablePartitions.size() &lt; 1) {</span></span>\n<span class="line"><span>                Integer random = Utils.toPositive(ThreadLocalRandom.current().nextInt());</span></span>\n<span class="line"><span>                newPart = random % partitions.size();</span></span>\n<span class="line"><span>            } else if (availablePartitions.size() == 1) {</span></span>\n<span class="line"><span>                newPart = ((PartitionInfo)availablePartitions.get(0)).partition();</span></span>\n<span class="line"><span>            } else {</span></span>\n<span class="line"><span>                while(newPart == null || newPart.equals(oldPart)) {</span></span>\n<span class="line"><span>                    int random = Utils.toPositive(ThreadLocalRandom.current().nextInt());</span></span>\n<span class="line"><span>                    newPart = ((PartitionInfo)availablePartitions.get(random % availablePartitions.size())).partition();</span></span>\n<span class="line"><span>                }</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            if (oldPart == null) {</span></span>\n<span class="line"><span>                this.indexCache.putIfAbsent(topic, newPart);</span></span>\n<span class="line"><span>            } else {</span></span>\n<span class="line"><span>                this.indexCache.replace(topic, prevPartition, newPart);</span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            return (Integer)this.indexCache.get(topic);</span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span>}</span></span></code></pre></div><ul><li>Nếu <code>keyBytes == null</code> thì sticky Partition Cache sẽ được thực hiện.</li><li><code>sticky Partition Cache</code> đơn giản như sau, Nếu có <code>oldPart</code> hiện trả về <code>oldPart</code> ====&gt; <code>return part == null ? this.nextPartition(topic, cluster, -1) : part;</code></li><li>Sẽ có 2 trường hợp để lấy về partition mới(Gọi method <code>nextPartition</code>) <ul><li><ol><li>Nếu <code>oldPart == null</code> tức chưa xác định partition thì sẽ lấy và partition mới ==&gt; trong method <code>partition</code> ở StickyPartitionCache</li></ol></li><li><ol start="2"><li>Khi đã đến ngưỡng của <code>BATCH_SIZE_CONFIG</code> trong flow thực hiện tạo lại batch thì sẽ xác định lại partition ==&gt; trong method <code>onNewBatch</code> ở <code>DefaultPartitioner</code></li></ol></li></ul></li><li>Chốt lại đơn giản là với sticky Partition Cache thì partition sẽ được tính theo <code>BATCH</code>, tất cả các <code>Record</code> có <code>key == null</code> thì tất cả các Record trong cùng <code>BATCH của cùng 1 topic</code> đó sẽ trên cùng một <code>partition</code></li></ul><h3 id="offsets" tabindex="-1">Offsets <a class="header-anchor" href="#offsets" aria-label="Permalink to &quot;Offsets&quot;">​</a></h3><ul><li>Khi broker thêm một Record nó sẽ thêm một <code>id</code> được gọi là <code>offset</code>. Một <code>offset</code> sẽ bắt đầu từ <code>0</code> và là number, nó sẽ tặng lên 1 mỗi khi thêm một Record. <img src="/assets/kafka-offset.sMIJqZq4.png" alt="kafka-offset.png"></li><li>Vì các Record mới luôn được thêm ở cuối của file, nên nó được sắp xếp theo offset.</li><li>Kafka đảm bảo Record order được sẵp xếp theo thứ tự trên cùng một partition chứ không phải trên các partition khác.</li></ul><details class="details custom-block"><summary>Ví dụ</summary><p>Có một topic với partition và có 10 Record.</p><ul><li>Partition 1: R1 (Offset 0) , R3(Offset 2) , R6(Offset 5), R7(Offset 6)</li><li>Partition 2:, R2(Offset 1), R4(Offset 3), R5(Offset 4), R8(Offset 7), R9(Offset 8), R10(Offset 9)</li></ul><p>Partition 1 và 2 sẽ có thứ tự offset tăng dần.</p></details><p>Consumer sử dụng <code>offset</code> để xác định vị trí của Record họ đã sử dụng, bằng cách này Consumer sẽ tìm các Record có <code>offset</code> cao hơn đã được Consumer đọc. <img src="/assets/kafka-offset-2.kQgsXxuz.png" alt="kafka-offset-2.png"></p><h3 id="xac-đinh-so-luong-partition-su-dung" tabindex="-1">Xác định số lượng partition sử dụng <a class="header-anchor" href="#xac-đinh-so-luong-partition-su-dung" aria-label="Permalink to &quot;Xác định số lượng partition sử dụng&quot;">​</a></h3><ul><li>Việc chọn số lượng partition khi tạo một topic là một điều khó khắn, nó là cả một nghệ thuật.</li><li>Một trong nhưng cân nhắc quan trọng là đầu tiên là <strong>lượng dữ liệu chạy chảy vào topic đó</strong>. Nhiều data thì chúng ta có thể có nhiều partition hơn để throughput(Thông lượng) cao hơn, tuy nhiên nhiều partition chúng ta cũng sẽ có những đánh đổi nhất định. <ul><li>Tăng số lượng partition sẽ tăng số lượng TCP connect và open file. Và thời gian để Consumer xử lý một Record cũng là một điều ảnh hưởng đến throughput. Nếu thời gian xử lý cần rất nhiều thì việc thêm partition có thể hữu ích nhưng việc xử lý chậm vẫn làm hiệu xuất không được tốt.</li></ul></li><li>Bắt đầu tốt nhất chúng ta nên sử dụng càng ít partition càng tốt. Bởi vì chúng ta có thể tăng số lượng partition nhưng không thể giảm partition.</li><li>Nếu khi tạo topic chúng ta có thể xác định số lượng Consumer thì chúng ta nên cài đặt partition bằng với số lượng của consumer. Điều này là best cho phiên bản kafk &lt; 2.4 bởi vì các phiên bản cũ sẽ <code>Round-robin</code> các partition nhưng ở phiên bản &gt;= 2.4 thì đã random partiton cho mỗi batch của topic.</li><li>Nếu topic này có thẻ Chúng ta sẽ có 1 chủ đề chi tiết hơn về điều này.</li></ul><h3 id="tao-mot-topic" tabindex="-1">Tạo một topic <a class="header-anchor" href="#tao-mot-topic" aria-label="Permalink to &quot;Tạo một topic&quot;">​</a></h3><ul><li>Để tạo một topic mới chúng ta có thể sử dụng cmd <code>kafka-topics</code> với param <code>--create</code>.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>kafka-topics --create --if-not-exists --topic first-topic\\ #1</span></span>\n<span class="line"><span>--bootstrap-server localhost:9092\\ #2 </span></span>\n<span class="line"><span>--replication-factor 1\\ #3  </span></span>\n<span class="line"><span>--partitions 1 #4</span></span></code></pre></div><ul><li><code>#1</code><ul><li>Với <code>kafka-topics</code> là câu lệnh để khởi chạy một <code>cmd</code></li><li><code>--create</code> là param để mong muốn tạo mới một topic với và <code>--if-not-exists</code> là param tạo nếu topic chưa tồn tại, còn đã tồn tại sẽ bỏ qua. (Nếu không có cờ này, nếu đã tồn tại sẽ trả về lỗi ngoại lệ <code>Error while executing topic command : Topic &#39;first-topic&#39; already exists.</code> )</li><li><code>--topic</code> là param để xác định tên topic</li><li><code>first-topic</code> là tên topic</li></ul></li><li><code>#2</code> với <code>--bootstrap-serve</code> là danh sách server kafka để <code>cmd</code> thực hiện kết nối để gửi request tạo topic</li><li><code>#3</code> với <code>--replication-factor</code> là số lượng replication để mỗi partition sễ được nhận rộng lên bao nhiêu. <ul><li>Là trị là số và phải ở giữa <code>1 và 32767</code></li><li>Số lượng phải nhỏ hơn hoặc bằng với số lượng Broker</li><li>Nếu không có parma này, default sẽ được lấy ở config trong Broker <code>default.replication.factor</code></li></ul></li><li><code>#4</code> với <code>--partitions 1</code> là số lượng partition cho topic này. Với số lượng cần lớn hơn <code>0</code><ul><li>Nếu không có parm này thì default sẽ được lấy trong <code>num.partitions</code></li></ul></li></ul><h3 id="segments" tabindex="-1">Segments <a class="header-anchor" href="#segments" aria-label="Permalink to &quot;Segments&quot;">​</a></h3><ul><li>Như chúng ta đã biết Broker sẽ thêm các Record vào các partition. Tuy nhiên Broker sẽ không thêm vào một tập partition duy nhất, nếu làm vậy tệp partition này sẽ khổng lồ.</li><li>Broker sẽ chia thành các tệp nhỏ thành các phần riêng biệt và được gọi là segments. <img src="/assets/kafka-partition-log-segments.48Zu1TVk.png" alt="kafka-partition-log-segments.png"><img src="/assets/kafka-partition-log-segments-file.24ReTyft.png" alt="kafka-partition-log-segments-file.png"></li><li>Việc sử dụng Segments sẽ giúp thực hiện push Record mới và thực hiện truy suất bản ghi bằng offset trở lên dễ dàng hơn.</li><li>Mặc định kafka Broker sẽ để mỗi segment là một 1G hoặc chúng ta có thể chỉ định ở <code>log.segment.bytes</code>. Khi đến ngưỡng segment sẽ được close và một segment mới được tạo. <ul><li>Kích thước segment nhỏ hơn có nghĩa là các tệp phải được đóng và phân bổ thường xuyên hơn, điều này làm giảm hiệu quả chung của việc ghi đĩa.</li></ul></li><li>Khi một segment bị close nó có thể được coi là expire(Hết hạn, bởi vì dữ liệu đã tồn tại quá lâu), việc điều chỉnh kích thước của các segment cũng rất quan trọng.</li><li>Chúng ta cũng có 1 config nữa đó là <code>log.segment.ms</code>, đây là thời gian nếu <code>segment</code> chưa đến ngưỡng giới hạn dung lượng thì kafka cũng sẽ close segment và tạo ra một segment mới. Default là 1 tuần.</li></ul><h2 id="mot-so-luu-y-ve-kafka-brokers" tabindex="-1">Một số lưu ý về Kafka Brokers <a class="header-anchor" href="#mot-so-luu-y-ve-kafka-brokers" aria-label="Permalink to &quot;Một số lưu ý về Kafka Brokers&quot;">​</a></h2><ul><li>Nếu tạo một Cluster kafka thì độ trễ của network nên ở mức dưới 15ms, vì việc liên lạc giữa các Kafka brokers là rất nhiều (Cả zookeeper nếu sử dụng zookeeper )</li></ul><h1 id="ref" tabindex="-1">REF: <a class="header-anchor" href="#ref" aria-label="Permalink to &quot;REF:&quot;">​</a></h1><ul><li><a href="https://ibm-cloud-architecture.github.io/refarch-eda/technology/kafka-overview/" target="_blank" rel="noreferrer">https://ibm-cloud-architecture.github.io/refarch-eda/technology/kafka-overview/</a></li><li><strong>Kafka book</strong>: <a href="/study/thanhlv-study-2024/static/Kafka%20Event%20Streaming%20Platform%20In%20Action.pdf">Kafka Event Streaming Platform In Action.pdf</a></li></ul>',46)];const o=n(e,[["render",function(n,t,s,e,o,r){return i(),a("div",null,c)}]]);export{s as __pageData,o as default};
